import { useEffect, useState } from "react";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";

export function RezervacijeRecepcionar() {
  const [rezervacije, setRezervacije] = useState([]);
  const [filterStatus, setFilterStatus] = useState("sve");
  const [poruka, setPoruka] = useState("");

  // Čitanje cookie-a da uzmemo id recepcionara
  const getCookie = (name) => {
    const match = document.cookie.match(new RegExp("(^| )" + name + "=([^;]+)"));
    if (match) return decodeURIComponent(match[2]);
    return null;
  };
  const idRecepcionara = getCookie("userId");

  // Učitavanje rezervacija
  useEffect(() => {
    fetch("http://localhost:8080/reservations/all")
      .then((res) => res.json())
      .then((data) => {
        if (data && data.data && data.data.values) {
          setRezervacije(data.data.values);
        }
      })
      .catch((err) => console.error("Greška pri učitavanju rezervacija:", err));
  }, []);

  // Filtriranje rezervacija po statusu
  const filtriraneRezervacije = rezervacije.filter((r) =>
    filterStatus === "sve" ? true : r.statusRezervacije === filterStatus
  );

  // Promena statusa rezervacije (npr. CONFIRMED ili CANCELLED)
  const promeniStatus = async (rezervacija, noviStatus) => {
    const updated = {
      ...rezervacija,
      statusRezervacije: noviStatus,
      idRecepcionar: idRecepcionara,
    };

    try {
      const res = await fetch("http://localhost:8080/reservations/update", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updated),
      });

      if (res.ok) {
        setRezervacije((prev) =>
          prev.map((r) =>
            r.idRezervacija === rezervacija.idRezervacija
              ? { ...r, statusRezervacije: noviStatus }
              : r
          )
        );
        setPoruka(`Rezervacija #${rezervacija.idRezervacija} ažurirana na ${noviStatus}.`);
        setTimeout(() => setPoruka(""), 4000);
      } else {
        setPoruka("Greška pri ažuriranju rezervacije.");
      }
    } catch (err) {
      console.error(err);
      setPoruka("Došlo je do greške pri ažuriranju.");
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        justifyContent: "space-between",
      }}
    >
      <NavBarRecepcionar />

      <div
        style={{
          backgroundImage: `url(${pattern})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: "100vh",
          padding: "40px",
        }}
      >
        <h2
          style={{
            textAlign: "center",
            color: "white",
            backgroundColor: "rgba(226, 108, 255, 0.7)",
            padding: "15px 30px",
            borderRadius: "10px",
            display: "inline-block",
            marginBottom: "30px",
          }}
        >
          Sve rezervacije
        </h2>

        {/* Poruka */}
        {poruka && (
          <div
            style={{
              backgroundColor: "rgba(255,255,255,0.8)",
              padding: "10px",
              borderRadius: "8px",
              marginBottom: "20px",
              textAlign: "center",
              color: "#4a148c",
              fontWeight: "bold",
            }}
          >
            {poruka}
          </div>
        )}

        {/* Filter */}
        <div style={{ textAlign: "center", marginBottom: "20px" }}>
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            style={{ padding: "10px", borderRadius: "5px", marginRight: "10px" }}
          >
            <option value="sve">Sve</option>
            <option value="CONFIRMED">Potvrđene</option>
            <option value="CANCELLED">Otkazane</option>
            <option value="CHECKED_IN">U toku</option>
            <option value="CHECKED_OUT">Završene</option>
            <option value="PENDING">Na čekanju</option>
          </select>
        </div>

        {/* Prikaz rezervacija */}
        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "20px",
            justifyContent: "center",
          }}
        >
          {filtriraneRezervacije.length === 0 ? (
            <p style={{ color: "white" }}>Nema pronađenih rezervacija.</p>
          ) : (
            filtriraneRezervacije.map((rez) => (
              <div
                key={rez.idRezervacija}
                style={{
                  backgroundColor: "rgba(255,255,255,0.9)",
                  width: "300px",
                  borderRadius: "10px",
                  padding: "15px",
                  textAlign: "left",
                  boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
                }}
              >
                <p>
                  <strong>ID:</strong> {rez.idRezervacija}
                </p>
                <p>
                  <strong>Gost:</strong>{" "}
                  {rez.gost?.ime && rez.gost?.prezime
                    ? `${rez.gost.ime} ${rez.gost.prezime}`
                    : rez.idGost}
                </p>
                <p>
                  <strong>Soba:</strong>{" "}
                  {rez.soba?.brojSobe || rez.idSoba || "N/A"}
                </p>
                <p>
                  <strong>Od:</strong> {rez.datumDolaska}
                </p>
                <p>
                  <strong>Do:</strong> {rez.datumOdlaska}
                </p>
                <p>
                  <strong>Status:</strong>{" "}
                  <span style={{ color: "#7b1fa2" }}>
                    {rez.statusRezervacije}
                  </span>
                </p>

                {/* Dugmad za akcije */}
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    marginTop: "10px",
                  }}
                >
                  <button
                    onClick={() => promeniStatus(rez, "CONFIRMED")}
                    style={{
                      backgroundColor: "#4caf50",
                      color: "white",
                      border: "none",
                      borderRadius: "5px",
                      padding: "5px 10px",
                      cursor: "pointer",
                    }}
                  >
                    Potvrdi
                  </button>

                  <button
                    onClick={() => promeniStatus(rez, "CANCELLED")}
                    style={{
                      backgroundColor: "#f44336",
                      color: "white",
                      border: "none",
                      borderRadius: "5px",
                      padding: "5px 10px",
                      cursor: "pointer",
                    }}
                  >
                    Otkaži
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      <Footer />
    </div>
  );
}
